import React, { useState, useEffect } from 'react';
import { useNavigate, Link, useLocation } from 'react-router-dom';
import { useDoctorRegistration } from '../../../context/doctorRegistrationContext';
import PublicLayout from '../../../components/layouts/publiclayout';
import StepIndicator from '../../../components/common/stepIndicator';
import DoctorProfessionalForm from '../../../components/forms/doctorProfessionalForm';
import '../../../styles/doctor/register/DotcotRegisterStep2.css';

const DoctorRegisterStep2: React.FC = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { updateProfessionalData, registrationData } = useDoctorRegistration();
    const [isLoading, setIsLoading] = useState(false);

    // Check if user has completed step 1
    useEffect(() => {
        if (!registrationData?.personal) {
            // Redirect to step 1 if no personal data
            navigate('/doctor/register/step1', { 
                state: { 
                    from: location.pathname,
                    message: 'Please complete personal information first' 
                } 
            });
        }
    }, [registrationData, navigate, location]);

    const handleSubmit = async (formData: any) => {
        setIsLoading(true);

        try {
            // Update registration context
            updateProfessionalData(formData);

            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 1500));

            // Navigate to verification step
            navigate('/doctor/register/step3');
        } catch (error) {
            console.error('Error saving professional data:', error);
            alert('An error occurred. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleBack = () => {
        navigate('/doctor/register/step1');
    };

    const steps = [
        { number: 1, label: 'Personal Info' },
        { number: 2, label: 'Professional Info' },
        { number: 3, label: 'Verification' }
    ];

    return (
        <PublicLayout>
            <main className="main-content">
                <div className="container">
                    <div className="registration-wrapper">
                        <StepIndicator 
                            currentStep={2} 
                            steps={steps}
                        />

                        <div className="form-container">
                            <div className="form-header">
                                <h1>Professional Information</h1>
                                <p>Step 2: Provide your medical qualifications and details</p>
                            </div>

                            <DoctorProfessionalForm 
                                onSubmit={handleSubmit}
                                isLoading={isLoading}
                                initialData={registrationData?.professional}
                                onBack={handleBack}
                                doctorName={registrationData?.personal?.fullName}
                            />
                        </div>
                    </div>
                </div>
            </main>
        </PublicLayout>
    );
};

export default DoctorRegisterStep2;
